const keywords = ["ai-operations-manager", "ai-project-manager", "ai-customer-success", "ai-implementation-specialist", "ai-strategy-consultant", "ai-solutions-manager", "generative-ai", "ai-consultant", "customer-success-manager", "project-coordinator", "operations-manager", "project-manager"];
return keywords.map(k => ({
  json: {
    url: `https://www.naukri.com/jobapi/v3/search?noOfResults=20&urlType=search_by_keyword&searchType=adv&keyword=${k}&location=delhi-ncr&pageNo=1&experience=2&exprangeFrom=2&exprangeTo=6&jobAge=1&sort=1`,
    label: k,
    source_platform: 'naukri'
  }
}));

const response = $input.first().json;
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

const jobs = [];
const listings = (response.jobDetails || response.jobs || []);

for (const job of listings) {
  jobs.push({
    job_id: job.jobId || job.id || '',
    job_title: job.title || job.jobTitle || '',
    company: job.companyName || job.company || '',
    location: (job.placeholders && job.placeholders[1] && job.placeholders[1].label) || job.location || '',
    job_url: job.jdURL || `https://www.naukri.com/job-listings-${job.jobId}`,
    description: job.jobDescription || job.description || '',
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

const fs = require('fs');
const path = require('path');

const cacheDir = 'C:/Users/Dev/Desktop/Job Agents/job-agent/setup/cache';
if (!fs.existsSync(cacheDir)) fs.mkdirSync(cacheDir, { recursive: true });

// Per-platform cache file
const item = $input.first().json;
const platform = item.source_platform || 'unknown';
const cacheFile = path.join(cacheDir, `seen_${platform.replace(/[^a-z0-9_]/gi, '_')}.json`);

let seen = [];
try { seen = JSON.parse(fs.readFileSync(cacheFile, 'utf-8')); } catch (e) {}

const url = item.job_url || item.job_id || '';
if (!url) return [];
if (seen.includes(url)) return []; // Already seen

seen.push(url);
if (seen.length > 5000) seen = seen.slice(-3000);
fs.writeFileSync(cacheFile, JSON.stringify(seen));

return [{ json: item }];
